import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Signup.css";

const Signup = () => {
  const [name, setName] = useState("");
  const [userType, setUserType] = useState("Student");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [libraryId, setLibraryId] = useState("LIB123456"); // Static Library ID for frontend
  const [showModal, setShowModal] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = (e) => {
    e.preventDefault();
    setShowModal(true);
  };

  const handleCloseModal = () => {
    setShowModal(false);
    navigate("/");
  };

  return (
    <div className="auth-container">
      <div className="auth-box">
        <h2>📖 Join the Library</h2>
        <form onSubmit={handleSubmit}>
          <input 
            type="text" 
            placeholder="Full Name" 
            value={name} 
            onChange={(e) => setName(e.target.value)} 
            required 
          />
         <select 
  value={userType} 
  onChange={(e) => setUserType(e.target.value)} 
  required
>
  <option value="" disabled>Select User Role</option>
  <option value="Student">Student</option>
  <option value="Faculty">Faculty</option>
  <option value="Librarian">Librarian (Admin)</option>
</select>
          <input 
            type="email" 
            placeholder="Email" 
            value={email} 
            onChange={(e) => setEmail(e.target.value)} 
            required 
          />
          <input 
            type="password" 
            placeholder="Password" 
            value={password} 
            onChange={(e) => setPassword(e.target.value)} 
            required 
          />
          <button type="submit">Sign Up</button>
        </form>
        <p>Already a member? <span onClick={() => navigate("/")}>Login</span></p>
      </div>

      {/* Modal for successful signup */}
      {showModal && (
        <div className="modal-overlay">
          <div className="modal">
            <h3>Signup Successful ✅</h3>
            <p>Your Library ID: <strong>{libraryId}</strong></p>
            <button onClick={handleCloseModal}>OK</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Signup;
